
class Scrollex {
  constructor(element, options) {
    this.element = element;
    this.state = false;
    this.options = Object.assign({
      top: 0,
      bottom: 0,
      mode: 'default', 
      enter: null,
      leave: null,
      initialize: null,
      terminate: null,
      scroll: null
    }, options);

    this._init();
  }





  _init() {
    if (this.options.initialize) this.options.initialize.call(this.element);

    const rootMargin = `${this._parseOffset(this.options.top)} 0px ${this._parseOffset(this.options.bottom)} 0px`;

    this.observer = new IntersectionObserver((entries) => {
      entries.forEach(entry => {
        const isIntersecting = entry.isIntersecting;

        if (isIntersecting !== this.state) {
          this.state = isIntersecting;
          if (this.state) {
            this.options.enter?.call(this.element);
          } else {
            this.options.leave?.call(this.element);
          }
        }

        if (this.options.scroll) {
          const progress = entry.intersectionRatio;
          this.options.scroll.call(this.element, progress);
        }
      });
    }, {
      rootMargin: rootMargin,
      threshold: this._getThresholds(this.options.mode)
    });

    this.observer.observe(this.element);
  }

  _parseOffset(val) {
    if (typeof val === 'string') return val;
    return `${val}px`;
  }

  _getThresholds(mode) {
    switch (mode) {
      case 'middle': return [0.5];
      case 'top':    return [0.01]; 
      case 'bottom': return [0.99];
      default:       return [0, 1];
    }
  }

  destroy() {
    this.observer.disconnect();
    this.options.terminate?.call(this.element);
  }
}

(function($) {
  $.fn.scrollex = function(options) {
    return this.each(function() {
      if (!$.data(this, 'scrollex')) {
        $.data(this, 'scrollex', new Scrollex(this, options));
      }
    });
  };

  $.fn.unscrollex = function() {
    return this.each(function() {
      const instance = $.data(this, 'scrollex');
      if (instance) {
        instance.destroy();
        $.removeData(this, 'scrollex');
      }
    });
  };
})(jQuery);
